	if workingDir != "" {
		return filepath.Base(workingDir)
	}
	if wd, err := os.Getwd(); err == nil {
		return filepath.Base(wd)
	}
	return DefaultPrefix
}

// workingDir returns the project root for git operations. When Dir is the
